class Solution {
public:
    int minSwaps(string s) {
        int mismatch = 0;
        int swaps = 0;
        for (char c : s) {
            if (c == '[') {
                mismatch++;
            } else {
                mismatch--;
            }
            if (mismatch < 0) {
                swaps++;
                mismatch++;
            }
        }
        return swaps;
    }
};
```
